const empleosContainer = document.querySelector("#empleos-container");
const selectEmpleos = document.querySelector("#select-empleos");

/**
 * Función auxiliar para convertir el texto largo de funciones en una lista (<ul>) de elementos (<li>).
 * @param {string} rawText El bloque de texto con saltos de línea.
 * @returns {HTMLUListElement} El elemento <ul> generado.
 */

function crearFuncionesLista(rawText) {
	const ul = document.createElement('ul');
    ul.classList.add('funciones-list');

    // Divide el texto por saltos de línea o por punto y seguido, luego filtra líneas vacías.
    const funcionesArray = rawText.split('\n').filter(line => line.trim() !== '');

    funcionesArray.forEach(funcText => {
        const li = document.createElement('li');
        li.textContent = funcText.trim();
        ul.appendChild(li);
    });

    return ul;
}

function crearEmpleo(item) {
	const card = document.createElement("div");
	card.classList.add("card");

	const titulo = document.createElement("h3");
	titulo.textContent = item.DENOMINACION;

	const subtitulo = document.createElement("p");
	subtitulo.classList.add("empleo-nivel");
	subtitulo.textContent = `Nivel ${item.NIVEL} | OPEC: ${item.OPEC}`;

	const detallesDiv = document.createElement("div");
	detallesDiv.classList.add("empleo-detalles");

	const salario = document.createElement("p");
	salario.classList.add("salario");
	salario.textContent = `Salario: ${item.SALARIO}`;

	const ciudades = document.createElement("p");
	ciudades.textContent = `Ciudades: ${item.CIUDADES}`;

    const vacantes = document.createElement("p");
	vacantes.textContent = `Vacantes: ${item.VACANTES}`;

    const inscritos = document.createElement("p");
	inscritos.textContent = item.INSCRITOS ? `Inscritos: ${item.INSCRITOS}` : "";

	const entidad = document.createElement("p");
	entidad.textContent = `Entidad: ${item.ENTIDAD}`;

    vacantes.classList.add("negrilla-big");
    inscritos.classList.add("negrilla-big");

	detallesDiv.appendChild(salario);
	detallesDiv.appendChild(vacantes);
	detallesDiv.appendChild(inscritos);
	detallesDiv.appendChild(ciudades);
	detallesDiv.appendChild(entidad);

	const requisitosDiv = document.createElement("div");
	requisitosDiv.classList.add("empleo-requisitos");

	const estudio = document.createElement("p");
	estudio.textContent = `Estudio: ${item.ESTUDIO}`;

	const experiencia = document.createElement("p");
	experiencia.textContent = `Experiencia: ${item.EXPERIENCIA}`;

	requisitosDiv.appendChild(estudio);
	requisitosDiv.appendChild(experiencia);

	const funcionesTitulo = document.createElement("h4");
	funcionesTitulo.textContent = "Funciones del Empleo";

    const funcionesLista = crearFuncionesLista(item.FUNCIONES || '');


	card.appendChild(titulo);
	card.appendChild(subtitulo);
	card.appendChild(detallesDiv);
	card.appendChild(requisitosDiv);
	card.appendChild(funcionesTitulo);
	card.appendChild(funcionesLista);

    return card;
}

function renderizarEmpleos(listaEmpleos) {
	//limpiar el contenido de los empleos anteriores (si tenia)
	while (empleosContainer.firstChild) {
		empleosContainer.removeChild(empleosContainer.firstChild);
	}

	//crear empleo
	listaEmpleos.forEach(empleo => {
		const empleoCard = crearEmpleo(empleo);
		empleosContainer.appendChild(empleoCard);
	})
}

selectEmpleos.addEventListener('change', (e) => {
	console.log(e.target.value);
	switch (e.target.value) {
		case "1":
			renderizarEmpleos(data.arquitectura);
			break;
		case "2":
			renderizarEmpleos(data.ingMecanica);
			break;
		case "3":
			renderizarEmpleos(data.asistencial)
	}
});

